//! AMQP exchange kinds: Direct, Topic, Headers, Fanout. The fanout case
//! delegates to the FOIL `fanout` primitive (race/fold/vent are sister
//! constructors per `Gnosis.WankelEngineTheorem.FiveForceLifecycleStage`).

/// AMQP exchange kind. Determines how the broker matches a message to
/// queues bound to the exchange.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum ExchangeKind {
    /// Direct exchange: binding key must equal routing key exactly.
    Direct,
    /// Topic exchange: binding key is a dotted pattern with `*` (one
    /// word) and `#` (zero+ words) wildcards.
    Topic,
    /// Headers exchange: match on the `headers` map (all-of: every
    /// declared header must match the message).
    Headers,
    /// Fanout exchange: every bound queue receives every message. Uses
    /// the FOIL `fanout` primitive in spirit (corridor green-window
    /// staggering across subscribers under the same admission rule).
    Fanout,
}

/// AMQP-style routing key. Dotted-segment string consumed by topic and
/// direct exchanges.
pub type RoutingKey = String;

/// A typed exchange descriptor — pairs name + kind. Constructors are
/// trivial; this is the type the broker stores in its exchange table.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct Exchange {
    /// Exchange name (empty = the default direct exchange per AMQP 0-9-1).
    pub name: String,
    /// Exchange kind.
    pub kind: ExchangeKind,
}

impl Exchange {
    /// Construct a direct exchange.
    pub fn direct(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            kind: ExchangeKind::Direct,
        }
    }
    /// Construct a topic exchange.
    pub fn topic(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            kind: ExchangeKind::Topic,
        }
    }
    /// Construct a fanout exchange.
    pub fn fanout(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            kind: ExchangeKind::Fanout,
        }
    }
    /// Construct a headers exchange.
    pub fn headers(name: impl Into<String>) -> Self {
        Self {
            name: name.into(),
            kind: ExchangeKind::Headers,
        }
    }
}
